Class Statistics Extends %RegisteredObject
{
    /// Calculate average of a list of numbers
    ClassMethod CalculateAverage(numbers As %ListOfDataTypes) As %Numeric
    {
        Set total = 0
        For i=1:1:numbers.Count() {
            Set total = total + numbers.GetAt(i)
        }
        // BUGGY: Division by zero when list is empty
        Quit total / numbers.Count()
    }
}

