Class TestStatistics Extends %RegisteredObject
{
    ClassMethod TestCalculateAverage()
    {
        // Test with values
        Set nums = ##class(%ListOfDataTypes).%New()
        Do nums.Insert(10)
        Do nums.Insert(20)
        Do nums.Insert(30)
        Set avg = ##class(Statistics).CalculateAverage(nums)
        If (avg '= 20) {
            Throw ##class(%Exception.General).%New("Average of 10,20,30 should be 20: got "_avg)
        }

        // Test empty list - should return 0, not error
        Set empty = ##class(%ListOfDataTypes).%New()
        Set avg = ##class(Statistics).CalculateAverage(empty)
        If (avg '= 0) {
            Throw ##class(%Exception.General).%New("Average of empty list should be 0: got "_avg)
        }
    }
}
